package com.vidaysalud.veterinaria.inventarioservicio.service;import com.vidaysalud.veterinaria.inventarioservicio.client.MedicamentoClient;import com.vidaysalud.veterinaria.inventarioservicio.dto.*;import com.vidaysalud.veterinaria.inventarioservicio.exception.*;import com.vidaysalud.veterinaria.inventarioservicio.model.*;import com.vidaysalud.veterinaria.inventarioservicio.repository.MovimientoInventarioRepository;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;@Service @RequiredArgsConstructor @Slf4j @Transactional public class InventarioService{private final MovimientoInventarioRepository r;private final MedicamentoClient client;@Transactional(readOnly=true)public List<MovimientoResponseDTO>listar(){return r.findAll().stream().map(this::dto).toList();}@Transactional(readOnly=true)public List<MovimientoResponseDTO>porMedicamento(Integer id){return r.findByIdMedicamentoOrderByFechaMovimientoDesc(id).stream().map(this::dto).toList();}public MovimientoResponseDTO registrar(MovimientoRequestDTO d){int anterior=client.obtenerStock(d.getIdMedicamento());int posterior=switch(d.getTipoMovimiento()){case ENTRADA->anterior+d.getCantidad();case SALIDA->anterior-d.getCantidad();case AJUSTE->d.getCantidad();};if(posterior<0)throw new ReglaNegocioException("Stock insuficiente para la salida");client.actualizarStock(d.getIdMedicamento(),posterior);MovimientoInventario m=MovimientoInventario.builder().idMedicamento(d.getIdMedicamento()).tipoMovimiento(d.getTipoMovimiento()).cantidad(d.getCantidad()).stockAnterior(anterior).stockPosterior(posterior).motivo(d.getMotivo()).build();m=r.save(m);log.info("Movimiento inventario id={} medicamento={} stock {}->{}",m.getIdMovimiento(),d.getIdMedicamento(),anterior,posterior);return dto(m);}@Transactional(readOnly=true)public MovimientoResponseDTO buscar(Integer id){return dto(r.findById(id).orElseThrow(()->new RecursoNoEncontradoException("Movimiento no encontrado: "+id)));}private MovimientoResponseDTO dto(MovimientoInventario m){return MovimientoResponseDTO.builder().idMovimiento(m.getIdMovimiento()).idMedicamento(m.getIdMedicamento()).tipoMovimiento(m.getTipoMovimiento()).cantidad(m.getCantidad()).stockAnterior(m.getStockAnterior()).stockPosterior(m.getStockPosterior()).fechaMovimiento(m.getFechaMovimiento()).motivo(m.getMotivo()).build();}}